B.XY=new A.a0("Uygunluk","Make Love\u2019\u0131 yaln\u0131zca 18 ya\u015f\u0131n\u0131 doldurmu\u015f ki\u015filer kullanabilir. Hesap olu\u015fturarak 18 ya\u015f\u0131ndan b\xfcy\xfck oldu\u011funu beyan edersin.")
B.Yj=new A.a0("Hesab\u0131n","Hesap bilgilerinin gizlili\u011finden ve hesab\u0131nda ger\xe7ekle\u015fen t\xfcm etkinliklerden sen sorumlusun. Bir ba\u015fkas\u0131 ad\u0131na sahte profil olu\u015fturamazs\u0131n.")
B.Y9=new A.a0("Davran\u0131\u015f kurallar\u0131","Taciz, nefret s\xf6ylemi, sahtek\xe2rl\u0131k, spam ve yasa d\u0131\u015f\u0131 i\xe7erik kesinlikle yasakt\u0131r. Bu kurallar\u0131 ihlal eden hesaplar uyar\u0131s\u0131z kapat\u0131labilir.")
B.Y7=new A.a0("Abonelikler","Premium abonelikler ilgili ma\u011faza (App Store / Google Play) \xfczerinden faturaland\u0131r\u0131l\u0131r ve otomatik yenilenir. \u0130ptal ma\u011faza ayarlar\u0131ndan yap\u0131l\u0131r.")
B.Yg=new A.a0("Sorumluluk reddi","Make Love bir tan\u0131\u015fma platformudur; kullan\u0131c\u0131lar aras\u0131ndaki etkile\u015fimlerden veya bulu\u015fmalardan do\u011fan durumlardan sorumlu de\u011fildir. G\xfcvenlik ipu\xe7lar\u0131m\u0131za uy.")
B.Yn=new A.a0("De\u011fi\u015fiklikler","Bu ko\u015fullar\u0131 zaman zaman g\xfcncelleyebiliriz. \xd6nemli de\u011fi\u015fikliklerde seni bilgilendiririz; kullanmaya devam etmen g\xfcncel ko\u015fullar\u0131 kabul etti\u011fin anlam\u0131na gelir.")
B.Q6=s([B.XY,B.Yj,B.Y9,B.Y7,B.Yg,B.Yn],t.Wy)
B.a9K=new A.Bn("Kullan\u0131m Ko\u015fullar\u0131",B.Q6)
B.XM=new A.a0("Veri sorumlusu","6698 say\u0131l\u0131 Ki\u015fisel Verilerin Korunmas\u0131 Kanunu (KVKK) kapsam\u0131nda ki\u015fisel verilerin, veri sorumlusu s\u0131fat\u0131yla Make Love taraf\u0131ndan a\u015fa\u011f\u0131da a\xe7\u0131klanan ama\xe7larla i\u015flenmektedir.")
B.XI=new A.a0("\u0130\u015flenen ki\u015fisel veriler","Kimlik (ad, ya\u015f, cinsiyet), ileti\u015fim (e-posta), profil ve kullan\u0131m verileri (ilgi alanlar\u0131, e\u015fle\u015fmeler, mesajlar) i\u015flenmektedir.")
B.XR=new A.a0("\u0130\u015fleme ama\xe7lar\u0131","Verilerin; \xfcyelik kayd\u0131n\u0131n olu\u015fturulmas\u0131, e\u015fle\u015ftirme hizmetinin sunulmas\u0131, g\xfcvenli\u011fin sa\u011flanmas\u0131 ve yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi amac\u0131yla i\u015flenir.")
B.XP=new A.a0("Hukuki sebep","Veriler, KVKK m.5 uyar\u0131nca s\xf6zle\u015fmenin kurulmas\u0131/ifas\u0131, me\u015fru menfaat ve a\xe7\u0131k r\u0131za hukuki sebeplerine dayan\u0131larak i\u015flenir.")
B.XU=new A.a0("Haklar\u0131n\u0131z (KVKK m.11)","Ki\u015fisel verilerinin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme, d\xfczeltilmesini veya silinmesini isteme, i\u015flemeye itiraz etme ve zarar\u0131n giderilmesini talep etme haklar\u0131na sahipsin.")
B.XS=new A.a0("Ba\u015fvuru","KVKK kapsam\u0131ndaki taleplerini destek@makelove.app adresine iletebilirsin. Ba\u015fvurun en ge\xe7 30 g\xfcn i\xe7inde sonu\xe7land\u0131r\u0131l\u0131r.")
B.SG=s([B.XM,B.XI,B.XR,B.XP,B.XU,B.XS],t.Wy)
B.a9L=new A.Bn("KVKK Ayd\u0131nlatma Metni",B.SG)
B.Y2=new A.a0("Hangi verileri toplar\u0131z?","Hesap olu\u015ftururken verdi\u011fin ad, ya\u015f, cinsiyet, e-posta ve profil bilgileri ile uygulamay\u0131 kullan\u0131rken olu\u015fan e\u015fle\u015fme, mesaj ve tercih verilerini toplar\u0131z.")
B.Yq=new A.a0("Verileri nas\u0131l kullan\u0131r\u0131z?","Verilerini sana en uygun profilleri g\xf6stermek, e\u015fle\u015fmeleri kurmak, g\xfcvenli\u011fi sa\u011flamak ve hizmeti geli\u015ftirmek i\xe7in kullan\u0131r\u0131z. \u0130zin vermedik\xe7e pazarlama amac\u0131yla \xfc\xe7\xfcnc\xfc taraflarla payla\u015fmay\u0131z.")
B.XZ=new A.a0("Payla\u015f\u0131m","Profilinde g\xf6sterdi\u011fin bilgiler di\u011fer kullan\u0131c\u0131larca g\xf6r\xfclebilir. Yasal y\xfck\xfcml\xfcl\xfckler d\u0131\u015f\u0131nda ki\u015fisel verilerini satmay\u0131z.")
B.XF=new A.a0("G\xfcvenlik","Sunucularla veri aktar\u0131m\u0131 TLS \u015fifrelemesiyle korunur ve verilerine yetkisiz eri\u015fimi \xf6nlemek i\xe7in makul \xf6nlemler al\u0131r\u0131z. Yine de hi\xe7bir sistem %100 g\xfcvenli de\u011fildir; g\xfc\xe7l\xfc bir \u015fifre kullanman\u0131 \xf6neririz.")
B.Ye=new A.a0("Konum ve \xfc\xe7\xfcnc\xfc taraflar",'\u015eehrini otomatik bulmak i\xe7in, yaln\u0131zca sen "Konumumu Bul" dedi\u011finde konum koordinatlar\u0131n \u015fehir \xe7\xf6z\xfcm\xfc amac\u0131yla OpenStreetMap (Nominatim) hizmetine g\xf6nderilir. Konum payla\u015f\u0131m\u0131 tamamen iste\u011fe ba\u011fl\u0131d\u0131r ve istedi\u011fin an vazge\xe7ebilirsin.')
B.Y_=new A.a0("Haklar\u0131n\u0131z","Verilerine eri\u015fme, d\xfczeltme ve silme talebinde bulunabilirsin. Hesab\u0131n\u0131 sildi\u011finde verilerin makul s\xfcre i\xe7inde kal\u0131c\u0131 olarak silinir.")
B.XD=new A.a0("\u0130leti\u015fim","Gizlilikle ilgili sorular i\xe7in destek@makelove.app adresine yazabilirsin.")
B.PW=s([B.Y2,B.Yq,B.XZ,B.XF,B.Ye,B.Y_,B.XD],t.Wy)
